/**
 * CategoryIcon — SVG icons for Paradocs phenomenon categories.
 *
 * These replace the emoji-based CATEGORY_ICONS system. Each icon is an inline
 * SVG that uses `currentColor` for fill, so it inherits text color from its
 * parent and works in both light and dark themes.
 *
 * Sources:
 *   - 4 from "Esoteric & Superstition Outline" pack (monochrome line art)
 *   - 1 from "Science Research" pack (DNA, normalized to mono)
 *   - 1 from "Paranormal & Supernatural" pack (possession, outlines only)
 *   - 1 from "Hell Icons" pack (hand with eye, outlines only)
 *   - 1 from "Intelligence Icons" pack (potential/brain, mono)
 *   - 1 from "Mythical Creatures" pack (Loch Ness monster, outlines only)
 *   - 1 from "Sensorial" pack (eye/vision, mono line art)
 *
 * Usage:
 *   <CategoryIcon category="ufos_aliens" size={24} />
 *   <CategoryIcon category="cryptids" className="text-amber-500" />
 */

import { PhenomenonCategory } from '@/lib/database.types'

interface CategoryIconProps {
  category: PhenomenonCategory
  /** Icon size in pixels (square). Default: 20 */
  size?: number
  className?: string
  /** For accessibility — set to "" to mark decorative */
  title?: string
}

export function CategoryIcon({
  category,
  size = 20,
  className = '',
  title,
}: CategoryIconProps) {
  const IconComponent = CATEGORY_SVG_MAP[category] || FallbackIcon
  return (
    <IconComponent
      width={size}
      height={size}
      className={className}
      title={title}
    />
  )
}

/** Emoji fallback map — for contexts where SVG can't render (emails, data) */
export const CATEGORY_EMOJI: Record<PhenomenonCategory, string> = {
  ufos_aliens: '🛸',
  cryptids: '🦶',
  ghosts_hauntings: '👻',
  psychic_phenomena: '🔮',
  consciousness_practices: '🧘',
  psychological_experiences: '🧠',
  biological_factors: '🧬',
  perception_sensory: '👁️',
  religion_mythology: '⚡',
  esoteric_practices: '✨',
  combination: '🔄',
}

// ─── SVG Icon Components ──────────────────────────────────────────

interface IconSvgProps {
  width: number
  height: number
  className?: string
  title?: string
}

function SvgWrap({
  children,
  viewBox = '0 0 512 512',
  ...props
}: IconSvgProps & { children: React.ReactNode; viewBox?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox={viewBox}
      width={props.width}
      height={props.height}
      className={props.className}
      fill="currentColor"
      aria-hidden={!props.title}
      role={props.title ? 'img' : undefined}
    >
      {props.title && <title>{props.title}</title>}
      {children}
    </svg>
  )
}

